(function(){function closeSidebar(){document.body.classList.remove("sidebar-open")}function toggleSidebar(){document.body.classList.toggle("sidebar-open")}document.addEventListener("click",function(event){var toggle=event.target.closest("[data-sidebar-toggle]");if(toggle){event.preventDefault();toggleSidebar();return}if(event.target.closest("[data-sidebar-close]")){closeSidebar()}});document.addEventListener("keydown",function(event){if(event.key==="Escape")closeSidebar()})})();
